import{_ as e,o as i,c as r,a0 as l}from"./chunks/framework.DgPozsi0.js";const u=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/02/reactDev_02_02.md","filePath":"pages/f2e/docReact/reactDev/02/reactDev_02_02.md"}'),t={name:"pages/f2e/docReact/reactDev/02/reactDev_02_02.md"};function s(o,a,h,d,c,n){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="從零開始建立-react-應用" tabindex="-1">從零開始建立 React 應用 <a class="header-anchor" href="#從零開始建立-react-應用" aria-label="Permalink to &quot;從零開始建立 React 應用&quot;">​</a></h1><p>如果現有框架無法滿足你應用的要求，或者你更喜歡自己構建框架，亦或者你只想學習 <code>React</code> 應用程序的基本知識，那麼你可以選擇從零開始構建 <code>React</code> 應用。</p><div class="info custom-block"><p class="custom-block-title">考慮使用框架</p><ul><li><p>從頭開始使用 <code>React</code> 是一種簡單的入門方式，但這通常相當於構建自己的臨時框架。隨著需求變化，你可能需要自行實現<code>服務器端渲染（SSR）</code>、<code>靜態站點生成（SSG）</code>、React 服務器組件（RSC）或未來的 React 新特性。</p></li><li><p>官方推薦的框架具備成熟的解決方案，能幫助減少或消除網絡請求中的瀑布效應以提升用戶體驗。選擇自建方式會使獲取支持變得更困難，因為你開發路由和數據獲取等功能的方式是獨特的。只有在能獨立解決這些問題，或確信永遠不需要這些功能時，才應該選擇此選項。</p></li></ul></div><h2 id="步驟-1-安裝建置工具" tabindex="-1">步驟 1 : 安裝建置工具 <a class="header-anchor" href="#步驟-1-安裝建置工具" aria-label="Permalink to &quot;步驟 1 : 安裝建置工具&quot;">​</a></h2><p>第一步是安裝一個構建工具，它們提供了打包、運行源代碼、本地開發伺服器以及生產環境的構建命令。</p><ul><li><h3 id="vite" tabindex="-1">Vite <a class="header-anchor" href="#vite" aria-label="Permalink to &quot;Vite&quot;">​</a></h3><ul><li><h4 id="簡介" tabindex="-1">簡介 <a class="header-anchor" href="#簡介" aria-label="Permalink to &quot;簡介&quot;">​</a></h4><p><a href="https://vite.dev/" target="_blank" rel="noreferrer">Vite</a> 旨在為現代網絡項目提供更快、更簡潔的開發體驗。</p></li><li><h4 id="安裝指令" tabindex="-1">安裝指令 <a class="header-anchor" href="#安裝指令" aria-label="Permalink to &quot;安裝指令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vite@latest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> react-ts</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="特點" tabindex="-1">特點 <a class="header-anchor" href="#特點" aria-label="Permalink to &quot;特點&quot;">​</a></h4><p>開箱即提供合理的默認配置，擁有豐富的插件生態系統，支持快速熱更新、<code>JSX</code>、<code>Babel/SWC</code>。它已被官方推薦的框架 <code>React Router</code> 所使用。</p></li></ul></li><li><h3 id="parcel" tabindex="-1">Parcel <a class="header-anchor" href="#parcel" aria-label="Permalink to &quot;Parcel&quot;">​</a></h3><ul><li><h4 id="簡介-1" tabindex="-1">簡介 <a class="header-anchor" href="#簡介-1" aria-label="Permalink to &quot;簡介&quot;">​</a></h4><p><a href="https://parceljs.org/" target="_blank" rel="noreferrer">Parcel</a> 結合了出色的開箱即用開發體驗和可擴展的架構，適合從小項目推向大規模生產應用。</p></li><li><h4 id="安裝指令-1" tabindex="-1">安裝指令 <a class="header-anchor" href="#安裝指令-1" aria-label="Permalink to &quot;安裝指令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> parcel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="特點-1" tabindex="-1">特點 <a class="header-anchor" href="#特點-1" aria-label="Permalink to &quot;特點&quot;">​</a></h4><p>支持快速刷新、<code>JSX</code>、<code>TypeScript</code>、<code>Flow</code> 和開箱即用的樣式。</p></li></ul></li><li><h3 id="rsbuild" tabindex="-1">Rsbuild <a class="header-anchor" href="#rsbuild" aria-label="Permalink to &quot;Rsbuild&quot;">​</a></h3><ul><li><h4 id="簡介-2" tabindex="-1">簡介 <a class="header-anchor" href="#簡介-2" aria-label="Permalink to &quot;簡介&quot;">​</a></h4><p><a href="https://rsbuild.dev/" target="_blank" rel="noreferrer">Rsbuild</a> 基於 <code>Rspack</code> 的構建工具，旨在為 <code>React</code> 應用程序提供無縫的開發體驗，配備精心調優的默認設置和現成的性能優化。</p></li><li><h4 id="安裝指令-2" tabindex="-1">安裝指令 <a class="header-anchor" href="#安裝指令-2" aria-label="Permalink to &quot;安裝指令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-rsbuild</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> react</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="特點-2" tabindex="-1">特點 <a class="header-anchor" href="#特點-2" aria-label="Permalink to &quot;特點&quot;">​</a></h4><p>內置對快速刷新、JSX、TypeScript 和樣式的支持。</p></li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">React Native 的 <code>Metro</code></p><p>如果從頭開始使用 <code>React Native</code>，需要使用其專屬的 JavaScript 打包工具 <code>Metro</code>（支持 iOS 和 Android 打包）。但與上述工具相比，它缺少許多功能。除非項目需要 React Native 支持，否則建議從 <code>Vite</code>、<code>Parcel</code> 或 <code>Rsbuild</code> 開始。</p></div><h2 id="步驟-2-構建常見的應用程式模式" tabindex="-1">步驟 2 : 構建常見的應用程式模式 <a class="header-anchor" href="#步驟-2-構建常見的應用程式模式" aria-label="Permalink to &quot;步驟 2 : 構建常見的應用程式模式&quot;">​</a></h2><p>上述構建工具僅從客戶端單頁應用程序（SPA）開始，不包含路由、數據獲取或樣式等常見功能的進一步解決方案。以下是生態系統中廣泛使用的工具：</p><ul><li><h3 id="路由" tabindex="-1">路由 <a class="header-anchor" href="#路由" aria-label="Permalink to &quot;路由&quot;">​</a></h3><ul><li><h4 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h4><p>路由決定了當用戶訪問特定 <code>URL</code> 時顯示的內容，處理嵌套路由、路由參數和查詢參數。路由通常與數據獲取（預取數據）、代碼拆分和頁面渲染方法集成在一起。</p></li><li><h4 id="推薦工具" tabindex="-1">推薦工具 <a class="header-anchor" href="#推薦工具" aria-label="Permalink to &quot;推薦工具&quot;">​</a></h4><ul><li><a href="https://reactrouter.com/start/data/custom" target="_blank" rel="noreferrer">React Router</a></li><li><a href="https://tanstack.com/router/latest" target="_blank" rel="noreferrer">Tanstack Router</a></li></ul></li></ul></li><li><h3 id="數據獲取" tabindex="-1">數據獲取 <a class="header-anchor" href="#數據獲取" aria-label="Permalink to &quot;數據獲取&quot;">​</a></h3><ul><li><h4 id="功能-1" tabindex="-1">功能 <a class="header-anchor" href="#功能-1" aria-label="Permalink to &quot;功能&quot;">​</a></h4><p>負責處理加載狀態、錯誤狀態以及緩存。</p></li><li><h4 id="提示" tabindex="-1">提示 <a class="header-anchor" href="#提示" aria-label="Permalink to &quot;提示&quot;">​</a></h4><p>直接在組件中獲取數據可能會導致網絡請求瀑布效應（加載時間變慢），官方建議儘可能在路由加載器或服務器上預取數據。</p></li><li><h4 id="推薦工具-依-api-類型劃分" tabindex="-1">推薦工具（依 API 類型劃分） <a class="header-anchor" href="#推薦工具-依-api-類型劃分" aria-label="Permalink to &quot;推薦工具（依 API 類型劃分）&quot;">​</a></h4><ul><li><h5 id="rest-風格-後端-api" tabindex="-1">REST 風格 / 後端 API <a class="header-anchor" href="#rest-風格-後端-api" aria-label="Permalink to &quot;REST 風格 / 後端 API&quot;">​</a></h5><ul><li><a href="https://tanstack.com/query/" target="_blank" rel="noreferrer">TanStack Query</a></li><li><a href="https://swr.vercel.app/" target="_blank" rel="noreferrer">SWR</a></li><li><a href="https://redux-toolkit.js.org/rtk-query/overview" target="_blank" rel="noreferrer">RTK Query</a></li></ul></li><li><h5 id="graphql-api" tabindex="-1">GraphQL API <a class="header-anchor" href="#graphql-api" aria-label="Permalink to &quot;GraphQL API&quot;">​</a></h5><ul><li><a href="https://www.apollographql.com/docs/react" target="_blank" rel="noreferrer">Apollo</a></li><li><a href="https://relay.dev/" target="_blank" rel="noreferrer">Relay</a></li></ul></li></ul></li></ul></li><li><h3 id="代碼拆分" tabindex="-1">代碼拆分 <a class="header-anchor" href="#代碼拆分" aria-label="Permalink to &quot;代碼拆分&quot;">​</a></h3><ul><li><h4 id="功能-2" tabindex="-1">功能 <a class="header-anchor" href="#功能-2" aria-label="Permalink to &quot;功能&quot;">​</a></h4><p>將應用程序分解為可以按需加載的小型包，以緩解代碼體積增大導致的加載緩慢。</p></li><li><h4 id="注意點" tabindex="-1">注意點 <a class="header-anchor" href="#注意點" aria-label="Permalink to &quot;注意點&quot;">​</a></h4><p>如果僅使用 <code>React.lazy</code> 懶加載組件（例如圖表），而圖表在渲染後才加載數據，會導致兩次等待的瀑布效應。應通過路由拆分代碼，並與打包、數據獲取集成。</p></li><li><h4 id="各工具參考文件" tabindex="-1">各工具參考文件 <a class="header-anchor" href="#各工具參考文件" aria-label="Permalink to &quot;各工具參考文件&quot;">​</a></h4><ul><li><a href="https://vite.dev/guide/features.html#build-optimizations" target="_blank" rel="noreferrer">Vite 構建優化</a></li><li><a href="https://parceljs.org/features/code-splitting/" target="_blank" rel="noreferrer">Parcel 代碼拆分</a></li><li><a href="https://rsbuild.dev/guide/optimization/code-splitting" target="_blank" rel="noreferrer">Rsbuild 代碼拆分</a></li></ul></li></ul></li><li><h3 id="提高應用程式效能" tabindex="-1">提高應用程式效能 <a class="header-anchor" href="#提高應用程式效能" aria-label="Permalink to &quot;提高應用程式效能&quot;">​</a></h3><p>由於上述構建工具默認僅支持單頁應用程序（<code>SPA</code>），你需要了解並實現其他渲染模式，以便在路由級別自由選擇渲染策略：</p><ul><li><h4 id="單頁面應用程序-spa" tabindex="-1">單頁面應用程序 (SPA) <a class="header-anchor" href="#單頁面應用程序-spa" aria-label="Permalink to &quot;單頁面應用程序 (SPA)&quot;">​</a></h4><p>加載單個 <code>HTML</code> 並動態更新。容易入門，但初始加載較慢。</p></li><li><h4 id="流式服務器端渲染-ssr" tabindex="-1">流式服務器端渲染 (SSR) <a class="header-anchor" href="#流式服務器端渲染-ssr" aria-label="Permalink to &quot;流式服務器端渲染 (SSR)&quot;">​</a></h4><p>在服務器上渲染完全部頁面再發送至客戶端。可提高性能，但維護極其複雜（可參見 <a href="https://vite.dev/guide/ssr" target="_blank" rel="noreferrer">Vite 的 SSR 指南</a>）。</p></li><li><h4 id="靜態站點生成-ssg" tabindex="-1">靜態站點生成 (SSG) <a class="header-anchor" href="#靜態站點生成-ssg" aria-label="Permalink to &quot;靜態站點生成 (SSG)&quot;">​</a></h4><p>在構建時生成靜態 <code>HTML</code> 文件。能提升特定頁面（如登錄頁）的性能（可參見 <a href="https://vite.dev/guide/ssr.html#pre-rendering-ssg" target="_blank" rel="noreferrer">Vite 的 SSG 指南</a>）。</p></li><li><h4 id="react-服務器组件-rsc" tabindex="-1">React 服務器组件 (RSC) <a class="header-anchor" href="#react-服務器组件-rsc" aria-label="Permalink to &quot;React 服務器组件 (RSC)&quot;">​</a></h4><p>允許在單個 <code>React</code> 樹中混合構建時、僅服務器和交互式組件。能減少打包體積並提高性能，但目前需要深入的專業知識來維護（可參見 <a href="https://github.com/parcel-bundler/rsc-examples" target="_blank" rel="noreferrer">Parcel 的 RSC 示例</a>）。</p></li></ul></li><li><h3 id="還有" tabindex="-1">還有... <a class="header-anchor" href="#還有" aria-label="Permalink to &quot;還有...&quot;">​</a></h3><p>從頭開始構建時會遇到許多限制，因為每個問題（路由、打包、數據獲取、渲染模式）都相互關聯，需要深度的專業知識。如果你不想自己解決這些聯動問題，官方建議從 <a href="/vitepress-study/pages/f2e/docReact/reactDev/02/reactDev_02_01.html">創建一個框架開始</a>。</p></li></ul>',10)])])}const b=e(t,[["render",s]]);export{u as __pageData,b as default};
